VALUES
  ('optometrist-moex-00624', 'optometrist', 'optometrist-moex-112-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '若在距離受測者眼前50公分處進行靜態視網膜檢影法（staticretinoscopy），並輔以+2.00DS之工作輔 助鏡片做檢測，當以垂直光條掃視眼底時，再以+2.00DS可達到中和眼底，若將+2.00DS移除，並改 用水平光條掃視眼底，結果可用-1.00DS達到中和眼底，則該眼的實際屈光異常度數為何？', '["PL/-3.00DC×090", "PL/-3.00DC×180", "+2.00DS/-3.00DC×090", "+2.00DS/-3.00DC×180"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "de77defa0606", "answer_pdf_sha1": "f4269bd76fc9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00625', 'optometrist', 'optometrist-moex-112-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '被檢者45歲，以暫時性閱讀附加鏡片+1.50 D檢查，NRA/PRA：+1.00D/-0.50D，其最終近距離附加 度數應為：', '["+1.25D", "+1.50D", "+1.75D", "+2.00D"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "de77defa0606", "answer_pdf_sha1": "f4269bd76fc9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00626', 'optometrist', 'optometrist-moex-112-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '以視網膜檢影鏡（retinoscope）驗光，驗光距離為 50 cm，利用光學十字標示法得到的結果為 +1.75D@120；-2.00D@030，其最後配鏡處方下列何者正確？', '["+1.75DS/-3.75DC×120", "-2.00DS/+3.75DC×120", "-2.00DS/+3.75DC×030", "-0.25DS/-3.75DC×120"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "de77defa0606", "answer_pdf_sha1": "f4269bd76fc9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00627', 'optometrist', 'optometrist-moex-112-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '除了調節（accommodation）以外，影響視網膜檢影鏡測量結果的因素不包括下列何者？', '["色彩像差（chromaticaberration）", "介質混濁（mediaopacities）", "傾斜角（obliquity）", "光條粗細（lightwidth）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "de77defa0606", "answer_pdf_sha1": "f4269bd76fc9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00628', 'optometrist', 'optometrist-moex-112-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '有關紅綠雙色檢查（bichrometest），下列敘述何者錯誤？', '["紅綠雙色檢查是用於檢驗最佳球面度數的一種方法", "測驗時需在室內較暗的條件下檢查", "指引患者看一行視力20/20紅綠背景視標", "雖然要辨識紅綠背景下的視標是否一樣清楚，色覺異常患者仍可以使用此種方法檢查"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "de77defa0606", "answer_pdf_sha1": "f4269bd76fc9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00629', 'optometrist', 'optometrist-moex-112-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '自覺式驗光步驟中，有關第二次球面度確認的敘述，下列何項錯誤？', '["前步驟可能調整了散光軸或散光度數，故需第二次球面度確認", "第二次球面度確認時，常用的霧視鏡片為+0.75DS至+1.00DS", "紅綠測試需於半暗室中進行，盡可能避免影響顏色飽和度", "若紅綠測試與最正球面度最佳視力（MPMVA）檢查結果有誤差，則以紅綠測試結果為準"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "de77defa0606", "answer_pdf_sha1": "f4269bd76fc9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00630', 'optometrist', 'optometrist-moex-112-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '運用傑克森交叉圓柱鏡幫患者檢測散光時，有關檢查技巧的敘述下列何者錯誤？', '["針對逆規（against-the-rule）散光患者，選用E、F、L、H等直線明顯的視標，較能精確檢測散光", "為維持最小模糊圈（thecircleofleastconfusion）位於視網膜上，選用圓形視標（circulartarget）檢查", "當患者有大於1.00D未矯正散光或低視力者，放上±0.25D交叉圓柱鏡檢查時，較不容易決定那一 鏡面比較清晰", "有短暫記憶障礙患者較不適合使用此法檢查散光度數與軸度，除非驗光室使用可產生兩圖比較的綜 合驗光儀（phoropter）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "de77defa0606", "answer_pdf_sha1": "f4269bd76fc9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00631', 'optometrist', 'optometrist-moex-112-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '用傑克森交叉圓柱鏡檢測法（JacksonCrossCylindertest,JCC）檢測散光度數時，下列敘述何者不適 當？', '["若欲檢測的散光值大於3.00D，則測量散光的角度軸時，應以小角度移動來修正角度軸，例如以5 度角慢慢移動檢查，不適合以15度大角度移動檢查", "散光度數越高時，角度軸越需以小角度表示。若散光度數大於5.00D，角度軸應以1度角表示；若 小於2.00D散光值，角度軸可以5度角表示", "確認散光度數值測量過程時，無須考量等效球面概念做散光度的測量調整", "測量散光時，應先測量散光角度軸後，再測量散光度數，才會檢測正確"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "de77defa0606", "answer_pdf_sha1": "f4269bd76fc9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00632', 'optometrist', 'optometrist-moex-112-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '以±0.25D之交叉圓柱鏡驗證散光度數，如初始驗光度數為-1.50DS/-1.50DC×100，當重複翻轉兩次交 叉圓柱鏡，修正兩次圓柱鏡度數，發現紅點位置在10度時，視標都會比較清楚，則驗光度數宜修正 為何？', '["-1.50DS/-1.00DC×100", "-1.50DS/-2.00DC×100", "-1.75DS/-1.00DC×100", "-1.25DS/-2.00DC×100"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "de77defa0606", "answer_pdf_sha1": "f4269bd76fc9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00633', 'optometrist', 'optometrist-moex-112-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '針孔視力的提升，對於下列何者情況不顯著？①視網膜病變  ②圓錐角膜  ③白內障  ④輕度近視散光', '["僅", "", "", "僅"]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:42+00:00", "source_pdf_sha1": "de77defa0606", "answer_pdf_sha1": "f4269bd76fc9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 24, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
